// hieu.asia — Nội dung trang ý nghĩa 64 quẻ Kinh Dịch (nâng cấp dữ liệu mỏng 2026-06).
// Trước đây mỗi quẻ chỉ có 1 dòng nghĩa trong engine backend (/tools/iching);
// đây là dữ liệu BIÊN TẬP viết thật từng quẻ cho thư viện trang tĩnh.
// id/name/nameVi/binary COPY CHÍNH XÁC từ bảng King Wen của backend
// (backend/infra/cloudflare/workers/api-gateway/src/tools/iching.ts) — đừng sửa lệch.
// binary: 6 ký tự đọc từ hào 6 (đỉnh) xuống hào 1 (đáy); 1 = dương (liền), 0 = âm (đứt).
// Giọng: phản tư, không phán — quẻ mô tả THẾ CỤC, người hỏi giữ quyết định.

export interface QueKinhDich {
  id: number; // 1–64 theo trình tự King Wen
  slug: string;
  name: string; // tên Hán-Việt ngắn ("Càn", "Truân"…)
  nameVi: string; // tên đầy đủ ("Thuần Càn", "Thủy Lôi Truân"…)
  binary: string; // hào 6 → hào 1
  keyTags: string[]; // 2–3 từ khóa
  tuong: string; // hình tượng quẻ (ý Đại Tượng truyện) — 1–2 câu
  core: string; // ý chính của thế cục — 3–4 câu, nghĩa hiện đại
  advice: string; // gợi ý ứng xử trong thế cục này
  love: string; // góc tình cảm – quan hệ
  work: string; // góc công việc – tiền bạc
  sequenceNote: string; // vị trí trong mạch Văn Vương: sau quẻ nào, đi cặp với quẻ nào (lật ngược / đảo âm dương), bước chuyển
  misread: string; // lỗi đọc quẻ này hay gặp + đính chính ngắn
  reflect: string[]; // câu hỏi tự soi
}

/** 8 quái cơ bản — tra từ 3 bit ("111" = Càn…). Dùng để render cấu trúc quẻ + hình hào. */
